+function parseCsv(text) {
+    const rows = [];
+    let row = [];
+    let field = "";
+    let inQuotes = false;
+
+    for (let i = 0; i < text.length; i += 1) {
+        const ch = text[i];
+
+        if (inQuotes) {
+            if (ch === '"') {
+                if (text[i + 1] === '"') {
+                    field += '"';
+                    i += 1;
+                } else {
+                    inQuotes = false;
+                }
+            } else {
+                field += ch;
+            }
+            continue;
+        }
+
+        if (ch === '"') {
+            inQuotes = true;
+            continue;
+        }
+
+        if (ch === ",") {
+            row.push(field);
+            field = "";
+            continue;
+        }
+
+        if (ch === "\n") {
+            row.push(field);
+            rows.push(row);
+            row = [];
+            field = "";
+            continue;
+        }
+
+        if (ch === "\r") {
+            continue;
+        }
+
+        field += ch;
+    }
+
+    if (field.length > 0 || row.length > 0) {
+        row.push(field);
+        rows.push(row);
+    }
+
+    return rows;
+}
+
+function extractFunctionIdentifiers(source) {
+    const names = [];
+
+    const declarationPattern = /\bfunction\s+([A-Za-z_$][\w$]*)\s*\(/g;
+    let match = declarationPattern.exec(source);
+    while (match) {
+        names.push(match[1]);
+        match = declarationPattern.exec(source);
+    }
+
+    const expressionPattern = /\b([A-Za-z_$][\w$]*)\s*=\s*function\s*\(/g;
+    match = expressionPattern.exec(source);
+    while (match) {
+        names.push(match[1]);
+        match = expressionPattern.exec(source);
+    }
+
+    return Array.from(new Set(names));
+}
+
+function hasNamedDeclaration(source, name) {
+    const escaped = name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
+    const declaration = new RegExp("\\bfunction\\s+" + escaped + "\\s*\\(");
+    const assignment = new RegExp("\\b" + escaped + "\\s*=\\s*function\\s*\\(");
+    return declaration.test(source) || assignment.test(source);
