"use strict";

const assert = require("assert");
const fs = require("fs");
const path = require("path");

const CSV_PATH = path.resolve(__dirname, "..", "temp_3.csv");

function runTest(name, fn) {
    try {
        fn();
        console.log("PASS", name);
    } catch (err) {
        console.error("FAIL", name);
        console.error(err && err.stack ? err.stack : err);
        process.exitCode = 1;
    }
}

function parseCsv(text) {
    const rows = [];
    let row = [];
    let field = "";
    let inQuotes = false;

    for (let i = 0; i < text.length; i += 1) {
        const ch = text[i];

        if (inQuotes) {
            if (ch === '"') {
                if (text[i + 1] === '"') {
                    field += '"';
                    i += 1;
                } else {
                    inQuotes = false;
                }
            } else {
                field += ch;
            }
            continue;
        }

        if (ch === '"') {
            inQuotes = true;
            continue;
        }

        if (ch === ",") {
            row.push(field);
            field = "";
            continue;
        }

        if (ch === "\n") {
            row.push(field);
            rows.push(row);
            row = [];
            field = "";
            continue;
        }

        if (ch === "\r") {
            continue;
        }

        field += ch;
    }

    if (field.length > 0 || row.length > 0) {
        row.push(field);
        rows.push(row);
    }

    return rows;
}

function extractFunctionIdentifiers(source) {
    const names = [];

    const declarationPattern = /\bfunction\s+([A-Za-z_$][\w$]*)\s*\(/g;
    let match = declarationPattern.exec(source);
    while (match) {
        names.push(match[1]);
        match = declarationPattern.exec(source);
    }

    const expressionPattern = /\b([A-Za-z_$][\w$]*)\s*=\s*function\s*\(/g;
    match = expressionPattern.exec(source);
    while (match) {
        names.push(match[1]);
        match = expressionPattern.exec(source);
    }

    return Array.from(new Set(names));
}

function hasNamedDeclaration(source, name) {
    const escaped = name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const declaration = new RegExp("\\bfunction\\s+" + escaped + "\\s*\\(");
    const assignment = new RegExp("\\b" + escaped + "\\s*=\\s*function\\s*\\(");
    return declaration.test(source) || assignment.test(source);
}

const csvText = fs.readFileSync(CSV_PATH, "utf8");
const rows = parseCsv(csvText);

runTest("csv has expected header", function() {
    assert.ok(rows.length > 1, "expected header and data rows");
    assert.strictEqual(rows[0][0], "method_definition");
    assert.strictEqual(rows[0][1], "method_code_neutralized");
});

const dataRows = rows.slice(1);

runTest("every row has both columns", function() {
    dataRows.forEach(function(cols, index) {
        assert.ok(cols.length >= 2, "row " + (index + 2) + " missing columns");
        assert.ok(cols[0].length > 0, "row " + (index + 2) + " method_definition is empty");
        assert.ok(cols[1].length > 0, "row " + (index + 2) + " method_code_neutralized is empty");
    });
});

let totalFunctions = 0;

dataRows.forEach(function(cols, rowIndex) {
    const methodDefinition = cols[0];
    const neutralizedCode = cols[1];
    const functions = extractFunctionIdentifiers(methodDefinition);

    runTest("row " + (rowIndex + 2) + " contains at least one function", function() {
        assert.ok(functions.length > 0, "no function signatures detected in method_definition");
    });

    functions.forEach(function(fnName) {
        totalFunctions += 1;

        runTest("row " + (rowIndex + 2) + " neutralizes function " + fnName, function() {
            assert.strictEqual(
                hasNamedDeclaration(neutralizedCode, fnName),
                false,
                "neutralized code still contains named function declaration/expression for " + fnName
            );
        });
    });
});

runTest("detected functions across dataset", function() {
    assert.ok(totalFunctions > 0, "expected at least one detected function");
});

