        }
        if (ch === "/" && next === "*") {
            i = skipBlockComment(source, i);
            continue;
        }
        if (ch === "{") {
            depth += 1;
            i += 1;
            continue;
        }
        if (ch === "}") {
            depth -= 1;
            i += 1;
            if (depth === 0) {
