        if (ch === "'" || ch === '"' || ch === "`") {
            i = skipString(source, i, ch);
            continue;
        }
        if (ch === "/" && next === "/") {
            i = skipLineComment(source, i);
            continue;
        }
        if (ch === "/" && next === "*") {
            i = skipBlockComment(source, i);
            continue;
        }
        if (ch === "{") {
            depth += 1;
            i += 1;
            continue;
        }
        if (ch === "}") {
            depth -= 1;
            i += 1;
