"use strict";

const vm = require("vm");
const { functionDefinitions } = require("./method-definitions.generated");

function instantiateFunction(source, originalName) {
  const context = vm.createContext({});
  const wrapped = "(function() {\n" + source + "\n; return typeof " + originalName + " !== \"undefined\" ? " + originalName + " : undefined;\n})()";
  const script = new vm.Script(wrapped);
  return script.runInContext(context, { timeout: 1000 });
}

describe("generated method_definition functions", () => {
  test("has extracted functions", () => {
    expect(Array.isArray(functionDefinitions)).toBe(true);
    expect(functionDefinitions.length).toBeGreaterThan(0);
  });

  functionDefinitions.forEach((entry) => {
    test(`${entry.exportName} compiles and instantiates`, () => {
      const compiled = new vm.Script(entry.source);
      expect(compiled).toBeDefined();
      const fn = instantiateFunction(entry.source, entry.originalName);
      expect(typeof fn).toBe("function");
    });
  });
});

