  { key: 'dataLayer', re: /\bdataLayer\b/g },
  { key: 'gtag', re: /\bgtag\b/g },
  { key: 'google_tag_manager', re: /google_tag_manager/g },
  { key: 'sendBeacon', re: /sendBeacon/g },
  { key: 'fetch', re: /\bfetch\s*\(/g },
  { key: 'XMLHttpRequest', re: /XMLHttpRequest/g },
  { key: 'cookie', re: /(?:document\s*(?:\.|\[\s*['\"])cookie|\bcookie\b)/g },
  { key: 'localStorage', re: /localStorage/g },
  { key: 'sessionStorage', re: /sessionStorage/g },
  { key: 'createElement(script)', re: /createElement\s*\(\s*['\"]script['\"]\s*\)/g },
  { key: 'appendChild', re: /appendChild/g },
  { key: 'getElementsByTagName(script)', re: /getElementsByTagName\s*\(\s*['\"]script['\"]\s*\)/g },
  { key: 'navigator', re: /\bnavigator\b/g },
  { key: 'eventBus', re: /eventBus/g },
  { key: 'metrics', re: /metrics/g },
  { key: 'flog', re: /flog/g },
  { key: 'track/tracking', re: /tracking|track/gi },
  { key: 'token', re: /token/gi },
  { key: 'captcha/challenge', re: /captcha|challenge/gi },
  { key: 'voucher', re: /voucher/gi },
  { key: 'waf', re: /\bwaf\b/gi },
  { key: 'beacon', re: /beacon/gi },
  { key: 'analytics', re: /analytics/gi },
  { key: 'script-src injection', re: /\.src\s*=|setAttribute\s*\(\s*['\"]src['\"]/g },
  { key: 'document access', re: /\bdocument\b/g },
  { key: 'window access', re: /\bwindow\b/g },
];

function countMatches(source, regex) {
  const m = source.match(regex);
  return m ? m.length : 0;
}

const scored = functionDefinitions.map((entry) => {
  const byIndicator = {};
  let total = 0;
  for (const ind of indicators) {
    const c = countMatches(entry.source, ind.re);
    if (c > 0) {
      byIndicator[ind.key] = c;
      total += c;
    }
  }
  return {
    exportName: entry.exportName,
    row: entry.row,
    originalName: entry.originalName,
    score: total,
    indicators: byIndicator,
    sourceLength: entry.source.length,
  };
});

const nonZero = scored.filter((x) => x.score > 0).sort((a, b) => b.score - a.score || a.exportName.localeCompare(b.exportName));
const top = nonZero.slice(0, 15);

const indicatorTotals = {};
for (const item of nonZero) {
  for (const [k, v] of Object.entries(item.indicators)) {
    indicatorTotals[k] = (indicatorTotals[k] || 0) + v;
  }
}
const topIndicators = Object.entries(indicatorTotals).sort((a, b) => b[1] - a[1]);

const reportPath = path.join(root, 'tracking-function-summary-report.md');

const lines = [];
lines.push('# Tracking Function Summary Report');
lines.push('');
lines.push('Source analyzed: `tests/method-definitions.generated.js`');
lines.push(`Generated: ${new Date().toISOString()}`);
lines.push('');
lines.push('## Overview');
lines.push(`- Total extracted functions: ${functionDefinitions.length}`);
lines.push(`- Functions with at least one tracking indicator: ${nonZero.length}`);
lines.push(`- Functions with no matched indicators: ${functionDefinitions.length - nonZero.length}`);
lines.push(`- Indicator patterns evaluated: ${indicators.length}`);
lines.push('');
lines.push('## Top Functions By Tracking Indicator Score');
lines.push('');
lines.push('| Rank | Export Name | Row | Original Name | Score | Matched Indicators |');
lines.push('|---:|---|---:|---|---:|---|');
for (let i = 0; i < top.length; i += 1) {
  const item = top[i];
  const detail = Object.entries(item.indicators)
    .sort((a, b) => b[1] - a[1])
    .map(([k, v]) => `${k}:${v}`)
    .join(', ');
  lines.push(`| ${i + 1} | ${item.exportName} | ${item.row} | ${item.originalName} | ${item.score} | ${detail} |`);
}
lines.push('');
lines.push('## Indicator Totals Across All Functions');
lines.push('');
lines.push('| Indicator | Total Matches |');
lines.push('|---|---:|');
for (const [name, total] of topIndicators) {
  lines.push(`| ${name} | ${total} |`);
}
lines.push('');
lines.push('## Notes');
lines.push('- This is a heuristic lexical scan, not full semantic classification.');
lines.push('- High scores indicate dense presence of tracking/network/storage/script-injection markers.');
lines.push('- Obfuscated functions may still contain tracking behavior that does not match these indicator patterns.');
lines.push('');

fs.writeFileSync(reportPath, lines.join('\n'), 'utf8');
console.log('Wrote', reportPath);
console.log('Top function:', top[0] ? `${top[0].exportName} (score ${top[0].score})` : 'none');
